import{_ as o,o as r,c as a,a2 as e}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"御花园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/yuhua-garden.md","filePath":"landmarks/forbidden-city/yuhua-garden.md","lastUpdated":1784720050000}'),n={name:"landmarks/forbidden-city/yuhua-garden.md"};function l(s,t,i,g,d,u){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="御花园" tabindex="-1">御花园 <a class="header-anchor" href="#御花园" aria-label="Permalink to &quot;御花园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1681495388843-42440711c89d?w=1200&amp;q=80" alt="御花园"></p><blockquote><p>红墙之内，一园收尽江南意。堆秀山的太湖石、钦安殿的玄武像、四百年的古柏藤萝——这是帝王的后花园。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>御花园位于紫禁城中轴线的最北端、坤宁宫之后，是故宫内廷的皇家花园，始建于明永乐十八年（1420年），与紫禁城同龄。它南北长约80米、东西宽约140米，占地约12000平方米——在偌大的紫禁城中，它只是一方小巧的天地，却以极高的密度汇聚了亭台楼阁、山石花木、铜像石刻二十余处景观，是中国古典皇家园林&quot;小中见大&quot;的典范。</p><p>与江南私家园林的自由曲折不同，御花园是<strong>中轴对称</strong>的皇家格局：中路以钦安殿为主殿，两侧建筑严格对称排布，在规整中点缀山石花木的灵动。这里是帝后茶余饭后的游憩之所，也是重阳节登高、七夕乞巧等节令活动的宫廷舞台。1925年故宫博物院成立后，御花园成为游客出神武门前最后的流连之地。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>占地面积</strong></td><td style="text-align:left;">约12000平方米</td></tr><tr><td style="text-align:left;"><strong>始建</strong></td><td style="text-align:left;">明永乐十八年（1420年）</td></tr><tr><td style="text-align:left;"><strong>布局</strong></td><td style="text-align:left;">中轴对称，以钦安殿为中心</td></tr><tr><td style="text-align:left;"><strong>建筑数量</strong></td><td style="text-align:left;">亭台楼阁二十余座</td></tr><tr><td style="text-align:left;"><strong>主殿</strong></td><td style="text-align:left;">钦安殿（供奉玄武大帝/真武大帝）</td></tr><tr><td style="text-align:left;"><strong>主山</strong></td><td style="text-align:left;">堆秀山（太湖石假山，山顶有御景亭）</td></tr><tr><td style="text-align:left;"><strong>古树</strong></td><td style="text-align:left;">四百年以上古柏、藤萝数十株</td></tr></tbody></table><p>御花园的景观可分三路：</p><ul><li><strong>中路</strong>：以<strong>钦安殿</strong>为核心，殿内供奉<strong>玄武大帝</strong>（真武大帝，北方之神），是紫禁城内最重要的道教神祇。殿为明代原构，盝顶形制，是故宫中少见的明代建筑遗存。殿前一对<strong>连理柏</strong>（两株古柏树干相交而生），被视为爱情与祥瑞的象征。</li><li><strong>东路</strong>：<strong>堆秀山</strong>是一座用太湖石堆叠而成的假山，山顶建有<strong>御景亭</strong>。每逢重阳节（农历九月初九），帝后登此亭远眺，取&quot;登高避灾&quot;之意——紫禁城内并无真山，堆秀山便是帝王&quot;不出宫而登高&quot;的替代品。山下有<strong>摛藻堂</strong>，为乾隆帝藏书之所。</li><li><strong>西路</strong>：<strong>延辉阁</strong>、<strong>位育斋</strong>等建筑错落分布，配以古柏、藤萝、铜鹿、铜鹤，营造出幽深静谧的园趣。园中有一株<strong>紫藤萝</strong>，据传植于明代，花开时满架紫云，是御花园最富诗意的春景。</li></ul><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="堆秀山-皇帝-不出宫的登高" tabindex="-1">堆秀山：皇帝&quot;不出宫的登高&quot; <a class="header-anchor" href="#堆秀山-皇帝-不出宫的登高" aria-label="Permalink to &quot;堆秀山：皇帝&quot;不出宫的登高&quot;&quot;">​</a></h3><p>重阳节登高是中国延续千年的节俗，但深居紫禁城的帝后不可能出城登山。于是，御花园东北角这座用江南太湖石堆叠而成的假山——堆秀山，便成了皇家的&quot;专属登山处&quot;。山顶的御景亭是全园制高点，重阳之日，帝后登亭饮菊花酒、佩茱萸囊，遥望宫墙外的秋色。一座几米高的假山承载了&quot;登高&quot;的全部仪式——礼制大于山水，这正是皇家园林与文人园林的根本分野。</p><h3 id="连理柏与紫藤萝-四百年的植物见证" tabindex="-1">连理柏与紫藤萝：四百年的植物见证 <a class="header-anchor" href="#连理柏与紫藤萝-四百年的植物见证" aria-label="Permalink to &quot;连理柏与紫藤萝：四百年的植物见证&quot;">​</a></h3><p>御花园中最动人的不是建筑，而是那些活过四百年的植物。钦安殿前的两株古柏，树干在中部交缠相连，被称为&quot;连理柏&quot;——&quot;在天愿作比翼鸟，在地愿为连理枝&quot;，帝后常以此树寄托恩爱之愿。而园中那株明代紫藤，每到暮春便垂下串串紫花，据记载已历经明清两代、四百余年春秋，是紫禁城最年长的&quot;居民&quot;之一。建筑会焚毁重建，这些古木却是真正的永乐遗民。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>堆秀山与御景亭</strong>：太湖石假山叠石嶙峋，山顶小亭是御花园的视觉高点，也是重阳节&quot;皇家登高&quot;的现场。</li><li><strong>钦安殿</strong>：供奉玄武大帝的明代原构，盝顶形制在故宫中独一无二，殿内神像与陈设保存完好。</li><li><strong>连理柏</strong>：钦安殿前两株交缠的古柏，是御花园最具象征意味的&quot;活文物&quot;。</li><li><strong>古藤萝</strong>：暮春时节满架紫花，是紫禁城内最富诗意的植物景观。</li><li><strong>对称中的灵动</strong>：漫步全园，感受&quot;皇家规制&quot;与&quot;园林野趣&quot;如何在方寸之间取得平衡。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>别赶路</strong>：御花园是故宫之行的收尾，多数游客匆匆穿过直奔神武门。放慢脚步，这里恰恰是整个皇宫中最松弛、最有人情味的空间。</li><li><strong>暮春与深秋最佳</strong>：四五月紫藤花开、九十月秋叶金黄，是御花园最美的季节。</li><li><strong>注意对称布局</strong>：站在中轴线上左右对照，会发现两侧建筑严格镜像——这是皇家园林区别于江南私园的标志，值得有意识地体会。</li><li><strong>出口选择</strong>：出神武门（北门）可顺游景山公园登顶俯瞰紫禁城全景；从御花园向东可折往珍宝馆方向（宁寿宫区）。</li><li><strong>铜像与石子路</strong>：留意园中的铜鹿、铜鹤和脚下的石子拼花路面——&quot;连生贵子&quot;&quot;麒麟送子&quot;等吉祥图案就铺在脚底。</li></ul><hr><p><strong>📍 位置</strong>：紫禁城中轴线最北端，坤宁宫之后 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/kunning-gong.html">坤宁宫</a>（经坤宁门进入） <strong>🔗 周边</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/zhenbao-guan.html">珍宝馆（宁寿宫区）</a>（向东） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',21)])])}const f=o(n,[["render",l]]);export{q as __pageData,f as default};
